import{_ as a,o as i,c as s,an as t}from"./chunks/framework.DTGE3tTv.js";const m=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md","lastUpdated":null}'),o={name:"benchmarks.md"};function r(n,e,c,h,l,d){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks {#benchmarks}&quot;">​</a></h1><p><code>ComposedDistributions</code> benchmarks its composition algebra to track performance over time.</p><h2 id="What-the-suite-covers" tabindex="-1">What the suite covers <a class="header-anchor" href="#What-the-suite-covers" aria-label="Permalink to &quot;What the suite covers {#What-the-suite-covers}&quot;">​</a></h2><ul><li><p><strong>Composition</strong>: construction, <code>rand</code>, and scoring (<code>logpdf</code>/<code>logccdf</code>) for one representative tree per composer — <a href="/previews/PR79/lib/public#ComposedDistributions.Sequential"><code>Sequential</code></a>, <a href="/previews/PR79/lib/public#ComposedDistributions.Parallel"><code>Parallel</code></a>, <a href="/previews/PR79/lib/public#ComposedDistributions.Resolve"><code>Resolve</code></a>, <a href="/previews/PR79/lib/public#ComposedDistributions.Compete"><code>Compete</code></a>, and <a href="/previews/PR79/lib/public#ComposedDistributions.Choose"><code>Choose</code></a> — plus the <a href="/previews/PR79/lib/public#ComposedDistributions.compose"><code>compose</code></a> front-end lowering a <code>NamedTuple</code> into a small nested (Parallel-of-Sequential/Resolve) tree, the shape of a typical onset → admission → outcome model.</p></li><li><p><strong>AD gradients</strong>: the same scenarios <code>test/ad/runtests.jl</code> exercises (a <code>Sequential</code> chain, a <code>Resolve</code> mixture marginal, and a <code>Compete</code> racing-hazard marginal), timed per AD backend (ForwardDiff, ReverseDiff, Mooncake, Enzyme). A (scenario, backend) pair is only benchmarked once its gradient is confirmed finite, so a backend that cannot yet handle a scenario is silently omitted rather than failing the run.</p></li></ul><h2 id="Running-the-suite-locally" tabindex="-1">Running the suite locally <a class="header-anchor" href="#Running-the-suite-locally" aria-label="Permalink to &quot;Running the suite locally {#Running-the-suite-locally}&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=benchmark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmark/run.jl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> results.json</span></span></code></pre></div><p>Or compare the working tree against another revision with <a href="https://github.com/MilesCranmer/AirspeedVelocity.jl" target="_blank" rel="noreferrer">AirspeedVelocity</a>&#39;s <code>benchpkg</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">benchpkg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rev=main,dirty</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --script=benchmark/benchmarks.jl</span></span></code></pre></div><h2 id="Reading-the-history" tabindex="-1">Reading the history <a class="header-anchor" href="#Reading-the-history" aria-label="Permalink to &quot;Reading the history {#Reading-the-history}&quot;">​</a></h2><p>The plot and table below are generated by the <code>benchmark-history</code> CI job on every push to <code>main</code> and on tagged releases, and published to the repo&#39;s <code>benchmarks</code> branch. Each point is a full run of the suite above at that revision; a rising line in a timing panel is a regression, a falling one an improvement.</p><h2 id="Performance-history" tabindex="-1">Performance history <a class="header-anchor" href="#Performance-history" aria-label="Permalink to &quot;Performance history {#Performance-history}&quot;">​</a></h2><p>The performance timeline (per-benchmark plots and a ratio table) is published to the <a href="https://github.com/EpiAware/ComposedDistributions.jl/tree/benchmarks/history" target="_blank" rel="noreferrer"><code>benchmarks</code> branch</a> on each push to <code>main</code> and each tagged release.</p>',12)])])}const b=a(o,[["render",r]]);export{m as __pageData,b as default};
